const dropdownButtons=document.querySelectorAll(".button--dropdown");dropdownButtons.length>0&&dropdownButtons.forEach(e=>{e.addEventListener("click",function(){this.classList.toggle("is-open")})});const dropdownFields=document.querySelectorAll(".field-dropdown");if(dropdownFields.length>0){function closeAllSelects(e=null){dropdownFields.forEach(o=>{o!==e&&o.classList.remove("is-open")})}dropdownFields.forEach(e=>{const o=e.querySelector("input");o.readOnly=!0,e.addEventListener("click",o=>{!o.target.closest(".dropdown-backdrop")||o.target.closest(".dropdown-backdrop__option")?(o.stopPropagation(),closeAllSelects(e),e.classList.toggle("is-open")):o.stopPropagation()});e.querySelectorAll(".dropdown-backdrop__option").forEach(t=>{t.addEventListener("click",s=>{s.stopPropagation(),e.querySelector(".dropdown-backdrop__option.selected")?.classList.remove("selected"),o.value="number"===o.type?t.textContent.trim().replace(/\s/g,""):t.textContent.trim(),t.classList.add("selected"),e.classList.add("selected"),e.classList.remove("is-open");const r=e.querySelector(".field-text__input");r&&(r.value="")})})})}document.addEventListener("click",()=>{closeAllSelects()});const burger=document.querySelector(".mobile-burger");burger&&burger.addEventListener("click",()=>{burger.classList.toggle("is-active")});const specialOffersSlider=new Swiper(".special-offers__slider",{slidesPerView:1.15,spaceBetween:8,navigation:{nextEl:".special-offers__next",prevEl:".special-offers__prev"},breakpoints:{480:{spaceBetween:12},768:{slidesPerView:3}}}),companiesSlider=new Swiper(".companies__slider",{slidesPerView:4,spaceBetween:9,breakpoints:{480:{spaceBetween:12},560:{slidesPerView:5},700:{slidesPerView:6},1440:{slidesPerView:8}}});